mapper.select:
SELECT a.id, a.title, a.slug, a.summary, a.cover_image, a.view_count, a.is_top, a.published_at, a.status, c.id AS cat_id, c.name AS cat_name, c.slug AS cat_slug, u.id AS author_id, u.nickname AS author_nickname, u.avatar AS author_avatar, t.id AS tag_id, t.name AS tag_name, t.slug AS tag_slug FROM article a LEFT JOIN category c ON a.category_id = c.id LEFT JOIN user u ON a.author_id = u.id LEFT JOIN article_tag at2 ON a.id = at2.article_id LEFT JOIN tag t ON at2.tag_id = t.id
AND a.status = #{status}
AND a.category_id = #{categoryId}
AND a.author_id = #{authorId}
ORDER BY a.updated_at DESC
